'use client'

import {
  cn,
  DismissableLayer,
  useAnchorPosition,
  useControllableSignal,
  useSignals,
} from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useId, useRef, type ReactNode } from 'react'
import styles from './toggletip.module.css'

export type ToggletipPlacement =
  | 'top'
  | 'bottom'
  | 'left'
  | 'right'
  | 'top-start'
  | 'top-end'
  | 'bottom-start'
  | 'bottom-end'

export interface ToggletipProps {
  /** The trigger node (e.g. an info icon). Rendered inside a button. */
  trigger: ReactNode
  /** The popover content. Interactive and selectable. */
  children: ReactNode
  placement?: ToggletipPlacement
  defaultOpen?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
  labels?: { label?: string }
  className?: string
}

export function Toggletip({
  trigger,
  children,
  placement = 'top',
  defaultOpen = false,
  open,
  onOpenChange,
  labels,
  className,
}: ToggletipProps) {
  useSignals()
  const [isOpen, setOpen] = useControllableSignal<boolean>({
    ...(open !== undefined && { value: open }),
    defaultValue: defaultOpen,
    ...(onOpenChange && { onChange: onOpenChange }),
  })

  const triggerRef = useRef<HTMLButtonElement>(null)
  const bubbleRef = useRef<HTMLDivElement>(null)
  const bubbleId = useId()

  const { anchorStyle, floatingStyle } = useAnchorPosition({
    anchorRef: triggerRef,
    floatingRef: bubbleRef,
    placement,
    enabled: isOpen,
  })

  return (
    <span className={cn(styles['root'], className)}>
      <button
        ref={triggerRef}
        type="button"
        className={styles['trigger']}
        aria-expanded={isOpen.value}
        aria-controls={bubbleId}
        aria-label={labels?.label ?? t(builtin.toggletip.label)}
        style={anchorStyle}
        onClick={() => setOpen(!isOpen.value)}
      >
        {trigger}
      </button>

      {isOpen.value ? (
        <DismissableLayer onDismiss={() => setOpen(false)}>
          <div
            ref={bubbleRef}
            id={bubbleId}
            role="status"
            data-state="open"
            data-placement={placement}
            className={styles['bubble']}
            style={floatingStyle}
          >
            {children}
          </div>
        </DismissableLayer>
      ) : null}
    </span>
  )
}

@layer cascivo.component {
  .root {
    position: relative;
    display: inline-flex;
  }

  .trigger {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: var(--cascivo-space-1);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    color: inherit;
    cursor: pointer;

    &:hover {
      background: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .bubble {
    z-index: var(--cascivo-z-tooltip);
    inline-size: max-content;
    max-inline-size: 18rem;
    margin: var(--cascivo-space-2);
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    line-height: var(--cascivo-leading-snug);
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-md);

    opacity: 1;
    translate: 0 0;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter);

    @starting-style {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-1));
    }
  }
}

@media (prefers-reduced-motion: reduce) {
  .bubble {
    transition: none;
  }
}

@media (forced-colors: active) {
  .trigger:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }

  .bubble {
    border: 1px solid CanvasText;
    background-color: Canvas;
    color: CanvasText;
  }
}
